const express = require('express');
const app = express();
const server = require('http').Server(app);
const io = require('socket.io')(server);

// Player authentication and session management
let players = {};

io.on('connection', (socket) => {
  console.log(`New player connected: ${socket.id}`);

  // Handle player disconnect
  socket.on('disconnect', () => {
    console.log(`Player disconnected: ${socket.id}`);
    delete players[socket.id];
  });

  // Handle player authentication
  socket.on('authenticate', (username, password) => {
    if (players[socket.id]) {
      players[socket.id].username = username;
      players[socket.id].password = password;
    } else {
      players[socket.id] = {
        username: username,
        password: password,
      };
    }
  });

  // Handle player move validation
  socket.on('move', (move) => {
    if (players[socket.id]) {
      const validMove = validateMove(move);
      if (validMove) {
        io.to(socket.id).emit('update', `Your move was accepted: ${JSON.stringify(move)}`);
      } else {
        io.to(socket.id).emit('error', 'Invalid move');
      }
    }
  });

  // Handle player score update
  socket.on('scoreUpdate', (score) => {
    if (players[socket.id]) {
      players[socket.id].score = score;
    }
  });
});

